mapper.select:
select t.id, t.project_id, t.user_id, t.task_name, t.assign_date, t.required_finish_date, t.actual_finish_date, t.duration_require, t.total_duration, t.status, t.extra_data::text as extra_data, t.del_flag, t.create_by, t.create_time, t.update_by, t.update_time, t.remark, p.project_name, u.user_name from proj_task t left join proj_project p on p.id = t.project_id left join sys_user u on u.user_id = t.user_id where t.del_flag = '0'
AND t.task_name like concat('%', #{taskName}, '%')
AND t.project_id = #{projectId}
AND t.user_id = #{userId}
AND t.status = #{status}
AND t.create_time >= to_timestamp(#{params.beginTime}, 'YYYY-MM-DD HH24:MI:SS')
AND t.create_time <= to_timestamp(#{params.endTime}, 'YYYY-MM-DD HH24:MI:SS')
order by t.create_time desc

mapper.update:
update proj_task
project_id = #{projectId}, user_id = #{userId}, task_name = #{taskName}, assign_date = #{assignDate}, required_finish_date = #{requiredFinishDate}, actual_finish_date = #{actualFinishDate}, duration_require = #{durationRequire}, total_duration = #{totalDuration}, status = #{status}, extra_data = #{extraData}::jsonb, remark = #{remark}, update_by = #{updateBy}, update_time = now()
where id = #{id}
